/**
 * My Number (マイナンバー) pattern
 * 12-digit individual number, can be formatted with or without hyphens/spaces
 */
const MY_NUMBER_PATTERN = /(?<!\d)(?:\d{4}[-\s]?\d{4}[-\s]?\d{4}|\d{12})(?!\d)/g;

/**
 * International phone number patterns
 * - E.164 format: +[country code][number] (e.g., +81-90-1234-5678)
 * - Common formats with country codes
 */
const INTERNATIONAL_PHONE_PATTERN =
  /\+[1-9]\d{0,2}[-\s.]?\(?\d{1,4}\)?[-\s.]?\d{1,4}[-\s.]?\d{1,9}/g;

// Order matters: more specific patterns should come first
const PII_PATTERNS = {
  email: /[\w.-]+@[\w.-]+\.\w+/g,
  internationalPhone: INTERNATIONAL_PHONE_PATTERN,
  creditCard: CREDIT_CARD_PATTERN,
  myNumber: MY_NUMBER_PATTERN,
  phone: /\d{2,4}-\d{2,4}-\d{4}/g,
  address:
    /(東京都|大阪府|京都府|兵庫県|奈良県|滋賀県|和歌山県|北海道|青森県|岩手県|宮城県|秋田県|山形県|福島県|茨城県|栃木県|群馬県|埼玉県|千葉県|神奈川県|新潟県|富山県|石川県|福井県|山梨県|長野県|岐阜県|静岡県|愛知県|三重県|鳥取県|島根県|岡山県|広島県|山口県|徳島県|香川県|愛媛県|高知県|福岡県|佐賀県|長崎県|熊本県|大分県|宮崎県|鹿児島県|沖縄県).+(市|区|町|村)/g,
};

export type PIIType =
  | 'email'
  | 'phone'
  | 'internationalPhone'
  | 'creditCard'
  | 'myNumber'
  | 'address';

export interface PIIDetectionResult {
  found: boolean;
  type?: PIIType;
  matches?: string[];
}

/**
 * Validate My Number using check digit algorithm
 * マイナンバーのチェックデジットを検証
 * @param number - 12-digit number string (digits only)
 * @returns true if check digit is valid
 */
function validateMyNumberCheckDigit(number: string): boolean {
  if (number.length !== 12) return false;

  const digits = number.split('').map(d => parseInt(d, 10));
  const checkDigit = digits[11];

  // Calculate check digit using the official algorithm
  // Weights for positions 1-11 are: 6,5,4,3,2,7,6,5,4,3,2
  const weights = [6, 5, 4, 3, 2, 7, 6, 5, 4, 3, 2];
  let sum = 0;

  for (let i = 0; i < 11; i++) {
    sum += digits[i] * weights[i];
  }

  const remainder = sum % 11;
  const expectedCheckDigit = remainder <= 1 ? 0 : 11 - remainder;

  return checkDigit === expectedCheckDigit;
}

/**
 * Basic Luhn algorithm check for credit card numbers
 * @param cardNumber - Credit card number (digits only)
 * @returns true if passes Luhn check
 */
function validateLuhn(cardNumber: string): boolean {
  const digits = cardNumber
    .split('')
    .reverse()
    .map(d => parseInt(d, 10));
  let sum = 0;

  for (let i = 0; i < digits.length; i++) {
    let digit = digits[i];
    if (i % 2 === 1) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
  }

  return sum % 10 === 0;
}

export function detectPII(text: string): PIIDetectionResult {
  for (const [type, pattern] of Object.entries(PII_PATTERNS)) {
    // Reset regex state
    pattern.lastIndex = 0;
    const matches = text.match(pattern);

    if (matches && matches.length > 0) {
      // Additional validation for specific types
      if (type === 'myNumber') {
        const validMatches = matches.filter(m => {
          const digitsOnly = m.replace(/[-\s]/g, '');
          return validateMyNumberCheckDigit(digitsOnly);
        });
        if (validMatches.length > 0) {
          return {
            found: true,
            type: type as PIIType,
            matches: validMatches,
          };
        }
        continue;
      }

      if (type === 'creditCard') {
        const validMatches = matches.filter(m => {
          const digitsOnly = m.replace(/[-\s]/g, '');
          return validateLuhn(digitsOnly);
        });
        if (validMatches.length > 0) {
          return {
            found: true,
            type: type as PIIType,
            matches: validMatches,
          };
        }
        continue;
      }

      return {
        found: true,
        type: type as PIIType,
        matches,
      };
    }
  }

  return { found: false };
}

